   430→func (d *deploymentTester) scaleDeployment(newReplicas int32) error {
   431→	var err error
   432→	d.deployment, err = d.updateDeployment(func(update *apps.Deployment) {
   433→		update.Spec.Replicas = &newReplicas
   434→	})
   435→	if err != nil {
