   534→func (d *deploymentTester) removeRSPods(ctx context.Context, replicaset *apps.ReplicaSet, count int, targetOnlyTerminating bool, gracePeriodSeconds int64) error {
   535→	selector, err := metav1.LabelSelectorAsSelector(replicaset.Spec.Selector)
   536→	if err != nil {
   537→		return fmt.Errorf("could not parse a selector for a replica set %q: %w", replicaset.Name, err)
   538→	}
   539→	pods, err := d.c.CoreV1().Pods(replicaset.Namespace).List(ctx, metav1.ListOptions{LabelSelector: selector.String()})
   540→	if err != nil {
   541→		return fmt.Errorf("failed to get pods for a replica set %q: %w", replicaset.Name, err)
   542→	}
   543→
   544→	for i, pod := range pods.Items {
   545→		if i >= count {
   546→			break
   547→		}
   548→		if targetOnlyTerminating && pod.DeletionTimestamp == nil {
   549→			continue
   550→		}
   551→		err := d.c.CoreV1().Pods(replicaset.Namespace).Delete(ctx, pod.Name, metav1.DeleteOptions{GracePeriodSeconds: ptr.To(gracePeriodSeconds)})
   552→		if err != nil {
   553→			return fmt.Errorf("failed to delete pod %q for a replica set %q: %w", pod.Name, replicaset.Name, err)
   554→		}
   555→	}
   556→
   557→	return nil
   558→}
