   399→func (d *deploymentTester) listUpdatedPods() ([]v1.Pod, error) {
   400→	selector, err := metav1.LabelSelectorAsSelector(d.deployment.Spec.Selector)
   401→	if err != nil {
   402→		return nil, fmt.Errorf("failed to parse deployment selector: %v", err)
   403→	}
   404→	pods, err := d.c.CoreV1().Pods(d.deployment.Namespace).List(context.TODO(), metav1.ListOptions{LabelSelector: selector.String()})
   405→	if err != nil {
   406→		return nil, fmt.Errorf("failed to list deployment pods, will retry later: %v", err)
   407→	}
   408→	newRS, err := d.getNewReplicaSet()
   409→	if err != nil {
   410→		return nil, fmt.Errorf("failed to get new replicaset of deployment %q: %v", d.deployment.Name, err)
   411→	}
   412→	if newRS == nil {
   413→		return nil, fmt.Errorf("unable to find new replicaset of deployment %q", d.deployment.Name)
   414→	}
   415→
   416→	var ownedPods []v1.Pod
   417→	for _, pod := range pods.Items {
   418→		rs := metav1.GetControllerOf(&pod)
   419→		if rs.UID == newRS.UID {
   420→			ownedPods = append(ownedPods, pod)
   421→		}
   422→	}
   423→	return ownedPods, nil
   424→}
   425→
   426→func (d *deploymentTester) waitRSStable(replicaset *apps.ReplicaSet) error {
   427→	return testutil.WaitRSStable(d.t, d.c, replicaset, pollInterval, pollTimeout)
   428→}
   429→
   430→func (d *deploymentTester) scaleDeployment(newReplicas int32) error {
   431→	var err error
   432→	d.deployment, err = d.updateDeployment(func(update *apps.Deployment) {
   433→		update.Spec.Replicas = &newReplicas
   434→	})
   435→	if err != nil {
   436→		return fmt.Errorf("failed updating deployment %q: %v", d.deployment.Name, err)
   437→	}
   438→
   439→	if err := d.waitForDeploymentCompleteAndMarkPodsReady(); err != nil {
   440→		return err
   441→	}
   442→
   443→	rs, err := d.expectNewReplicaSet()
   444→	if err != nil {
   445→		return err
   446→	}
   447→	if *rs.Spec.Replicas != newReplicas {
   448→		return fmt.Errorf("expected new replicaset replicas = %d, got %d", newReplicas, *rs.Spec.Replicas)
   449→	}
   450→	return nil
   451→}
   452→
   453→// waitForReadyReplicas waits for number of ready replicas to equal number of replicas.
   454→func (d *deploymentTester) waitForReadyReplicas() error {
   455→	if err := wait.PollImmediate(pollInterval, pollTimeout, func() (bool, error) {
   456→		deployment, err := d.c.AppsV1().Deployments(d.deployment.Namespace).Get(context.TODO(), d.deployment.Name, metav1.GetOptions{})
   457→		if err != nil {
   458→			return false, fmt.Errorf("failed to get deployment %q: %v", d.deployment.Name, err)
   459→		}
   460→		return deployment.Status.ReadyReplicas == *deployment.Spec.Replicas, nil
   461→	}); err != nil {
   462→		return fmt.Errorf("failed to wait for .readyReplicas to equal .replicas: %v", err)
   463→	}
   464→	return nil
   465→}
   466→
   467→// markUpdatedPodsReadyWithoutComplete marks updated Deployment pods as ready without waiting for deployment to complete.
   468→func (d *deploymentTester) markUpdatedPodsReadyWithoutComplete() error {
   469→	if err := wait.PollImmediate(pollInterval, pollTimeout, func() (bool, error) {
   470→		pods, err := d.listUpdatedPods()
   471→		if err != nil {
   472→			return false, err
   473→		}
   474→		for i := range pods {
   475→			pod := pods[i]
   476→			if podutil.IsPodReady(&pod) {
   477→				continue
   478→			}
   479→			if err = markPodReady(d.c, d.deployment.Namespace, &pod); err != nil {
   480→				d.t.Logf("failed to update Deployment pod %q, will retry later: %v", pod.Name, err)
   481→				return false, nil
   482→			}
   483→		}
   484→		return true, nil
   485→	}); err != nil {
   486→		return fmt.Errorf("failed to mark all updated pods as ready: %v", err)
   487→	}
   488→	return nil
   489→}
   490→
   491→// waitForReadyReplicas waits for number of ready replicas to equal number of replicas.
   492→func (d *deploymentTester) waitForDeploymentStatusReplicasFields(ctx context.Context, replicas, updatedReplicas, readyReplicas, availableReplicas, unavailableReplicas int32, terminatingReplicas *int32) error {
   493→	var lastErr error
   494→	err := wait.PollUntilContextTimeout(ctx, pollInterval, pollTimeout, true, func(_ context.Context) (bool, error) {
   495→		// do not pass ctx to checkDeploymentStatusReplicasFields (Deployments().Get) so we always obtain the latest error and not the one from deadline exceeded
   496→		lastErr = d.checkDeploymentStatusReplicasFields(replicas, updatedReplicas, readyReplicas, availableReplicas, unavailableReplicas, terminatingReplicas)
   497→		return lastErr == nil, nil
   498→	})
   499→	if err != nil {
   500→		return fmt.Errorf("%w: %w", lastErr, err)
   501→	}
   502→	return nil
   503→}
   504→
   505→// Verify all replicas fields of DeploymentStatus have desired count.
   506→// Immediately return an error when found a non-matching replicas field.
   507→func (d *deploymentTester) checkDeploymentStatusReplicasFields(replicas, updatedReplicas, readyReplicas, availableReplicas, unavailableReplicas int32, terminatingReplicas *int32) error {
   508→	deployment, err := d.c.AppsV1().Deployments(d.deployment.Namespace).Get(context.TODO(), d.deployment.Name, metav1.GetOptions{})
   509→	if err != nil {
   510→		return fmt.Errorf("failed to get deployment %q: %v", d.deployment.Name, err)
   511→	}
   512→	if deployment.Status.Replicas != replicas {
   513→		return fmt.Errorf("unexpected .replicas: expect %d, got %d", replicas, deployment.Status.Replicas)
   514→	}
   515→	if deployment.Status.UpdatedReplicas != updatedReplicas {
   516→		return fmt.Errorf("unexpected .updatedReplicas: expect %d, got %d", updatedReplicas, deployment.Status.UpdatedReplicas)
   517→	}
   518→	if deployment.Status.ReadyReplicas != readyReplicas {
   519→		return fmt.Errorf("unexpected .readyReplicas: expect %d, got %d", readyReplicas, deployment.Status.ReadyReplicas)
   520→	}
   521→	if deployment.Status.AvailableReplicas != availableReplicas {
   522→		return fmt.Errorf("unexpected .availableReplicas: expect %d, got %d", availableReplicas, deployment.Status.AvailableReplicas)
   523→	}
   524→	if deployment.Status.UnavailableReplicas != unavailableReplicas {
   525→		return fmt.Errorf("unexpected .unavailableReplicas: expect %d, got %d", unavailableReplicas, deployment.Status.UnavailableReplicas)
   526→	}
   527→	if !ptr.Equal(deployment.Status.TerminatingReplicas, terminatingReplicas) {
   528→		return fmt.Errorf("unexpected .terminatingReplicas: expect %v, got %v", ptr.Deref(terminatingReplicas, -1), ptr.Deref(deployment.Status.TerminatingReplicas, -1))
   529→
   530→	}
   531→	return nil
   532→}
   533→
   534→func (d *deploymentTester) removeRSPods(ctx context.Context, replicaset *apps.ReplicaSet, count int, targetOnlyTerminating bool, gracePeriodSeconds int64) error {
   535→	selector, err := metav1.LabelSelectorAsSelector(replicaset.Spec.Selector)
   536→	if err != nil {
   537→		return fmt.Errorf("could not parse a selector for a replica set %q: %w", replicaset.Name, err)
   538→	}
   539→	pods, err := d.c.CoreV1().Pods(replicaset.Namespace).List(ctx, metav1.ListOptions{LabelSelector: selector.String()})
   540→	if err != nil {
   541→		return fmt.Errorf("failed to get pods for a replica set %q: %w", replicaset.Name, err)
   542→	}
   543→
   544→	for i, pod := range pods.Items {
   545→		if i >= count {
   546→			break
   547→		}
   548→		if targetOnlyTerminating && pod.DeletionTimestamp == nil {
   549→			continue
   550→		}
   551→		err := d.c.CoreV1().Pods(replicaset.Namespace).Delete(ctx, pod.Name, metav1.DeleteOptions{GracePeriodSeconds: ptr.To(gracePeriodSeconds)})
   552→		if err != nil {
   553→			return fmt.Errorf("failed to delete pod %q for a replica set %q: %w", pod.Name, replicaset.Name, err)
   554→		}
   555→	}
   556→
   557→	return nil
   558→}
